## Implementation Steps

### Step 1: Create Storage Utility

**File:** `src/utils/sessionStore.ts` (NEW)

```typescript
export function readJson<T>(key: string): T | null {
  try {
    const data = sessionStorage.getItem(key);
    return data ? JSON.parse(data) : null;
  } catch {
    return null;
  }
}

export function writeJson<T>(key: string, value: T): void {
  try {
    sessionStorage.setItem(key, JSON.stringify(value));
  } catch (e) {
    console.warn('sessionStorage write failed:', e);
  }
}

export function remove(key: string): void {
  sessionStorage.removeItem(key);
}
```

### Step 2: Create High Score Hook

**File:** `src/hooks/useSessionHighScore.ts` (NEW)

```typescript
import { useState, useEffect, useCallback } from 'react';
import { readJson, writeJson } from '@/utils/sessionStore';

const HIGH_SCORE_KEY = 'flowerDefense_highScore_v2';

export interface HighScoreData {
  score: number;
  initials: string;
  level: number;
  timestamp: number;
  startedAtLevel: number;
}

export function useSessionHighScore() {
  const [highScore, setHighScore] = useState<HighScoreData | null>(null);

  useEffect(() => {
    setHighScore(readJson<HighScoreData>(HIGH_SCORE_KEY));
  }, []);

  const checkEligibility = useCallback((startedAtLevel: number) => {
    return startedAtLevel === 0; // Only Level 1 starts qualify
  }, []);

  const evaluateScore = useCallback((
    score: number,
    level: number,
    startedAtLevel: number
  ) => {
    if (!checkEligibility(startedAtLevel)) {
      return { isNewHighScore: false, previous: highScore };
    }
    const isNewHighScore = !highScore || score > highScore.score;
    return { isNewHighScore, previous: highScore };
  }, [highScore, checkEligibility]);

  const saveHighScore = useCallback((data: Omit<HighScoreData, 'timestamp'>) => {
    const fullData: HighScoreData = {
      ...data,
      timestamp: Date.now(),
    };
    writeJson(HIGH_SCORE_KEY, fullData);
    setHighScore(fullData);
  }, []);

  return {
    highScore,
    checkEligibility,
    evaluateScore,
    saveHighScore,
  };
}
```

